// src/context/AuthContext.js
import { createContext, useContext, useEffect, useState } from "react";
import { getAuth, onAuthStateChanged, signOut } from "firebase/auth";
import { getDatabase, ref, get, child } from "firebase/database";
import { app } from "../firebase"; // Đảm bảo đường dẫn import đúng file firebase.js của bạn

const AuthContext = createContext();

export const useAuth = () => {
  return useContext(AuthContext);
};

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);
  
  const auth = getAuth(app);
  const db = getDatabase(app);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        try {
          // Lấy thêm thông tin role từ Realtime Database
          // Giả sử cấu trúc DB là users/{uid}/role
          const dbRef = ref(db);
          const userSnapshot = await get(child(dbRef, `users/${user.uid}`));
          
          if (userSnapshot.exists()) {
            const userData = userSnapshot.val();
            // Gộp thông tin từ Auth và Database
            setCurrentUser({ ...user, ...userData });
          } else {
            // Trường hợp user có trong Auth nhưng chưa có trong Database
            setCurrentUser(user);
          }
        } catch (error) {
          console.error("Lỗi khi lấy dữ liệu user:", error);
          setCurrentUser(user);
        }
      } else {
        setCurrentUser(null);
      }
      setLoading(false); // Đã tải xong
    });

    return unsubscribe;
  }, [auth, db]);

  const logout = () => {
    return signOut(auth);
  };

  const value = {
    currentUser,
    loading,
    logout
  };

  // Chỉ render children khi đã tải xong dữ liệu để tránh lỗi null
  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};
